powerpagecomponent.content:
{
  "copy": "{% assign page_title = "New service request" %} {% assign homeurl = website.adx_partialurl %}

<section class="esi-hero">
  <div class="esi-hero-inner">
    <div class="esi-hero-copy">
      <h1>Submit a service request</h1>
      <p>Use this secure form to describe what you need, explain the impact, attach supporting files, and see an estimated response path before you submit.</p>
    </div>
    {% if user %}
    <div class="esi-user-card" aria-label="Signed in customer">
      <span class="esi-user-label">Signed in</span>
      <strong>{{ user.fullname | default: user.emailaddress1 | escape }}</strong>
      <span>Customer account</span>
    </div>
    {% endif %}
  </div>
</section>

{% if user %}
<main class="esi-shell" id="mainContent" data-esi-intake>
  <div class="esi-workspace-banner">
    <div>
      <strong>Secure customer request</strong>
      <span>Your request is linked to your account so you can return later and track updates.</span>
    </div>
    <span class="esi-status-pill">Signed in</span>
  </div>

  <nav class="esi-steps" aria-label="Request steps">
    <button type="button" class="is-active" data-step-target="details" aria-current="step">
      <span class="esi-step-index">1</span>
      <span><strong>Request Details</strong><small>What do you need?</small></span>
    </button>
    <button type="button" data-step-target="impact">
      <span class="esi-step-index">2</span>
      <span><strong>Impact and Urgency</strong><small>Who is affected?</small></span>
    </button>
    <button type="button" data-step-target="documents">
      <span class="esi-step-index">3</span>
      <span><strong>Supporting Files</strong><small>Prepare upload</small></span>
    </button>
    <button type="button" data-step-target="review">
      <span class="esi-step-index">4</span>
      <span><strong>Review and Submit</strong><small>Confirm details</small></span>
    </button>
  </nav>

  <div class="esi-layout">
    <form class="esi-form" novalidate>
      <section class="esi-step is-active" data-step="details">
        <div class="esi-section-heading">
          <span class="esi-section-kicker">Step 1 of 4</span>
          <h2>Request details</h2>
          <p>Start with a short title, category, and clear description so we understand what you need.</p>
        </div>

        <label>
          <span>Request title <em>Required</em></span>
          <input name="title" type="text" required maxlength="200" autocomplete="off" placeholder="Example: Unable to access partner reporting dashboard" />
        </label>

        <label>
          <span>Service category <em>Required</em></span>
          <select name="category" data-routing-input required>
            <option value="">Loading categories...</option>
          </select>
        </label>

        <label>
          <span>Description <em>Required</em></span>
          <textarea name="description" rows="6" required placeholder="Describe the issue, request, or service need. Include affected program, account, or timeline details where helpful."></textarea>
        </label>

        <div class="esi-step-error" data-step-error role="alert"></div>
        <div class="esi-action-bar">
          <span>Next: impact and urgency</span>
          <button type="button" class="esi-primary" data-next-step="impact">Continue to impact</button>
        </div>
      </section>

      <section class="esi-step" data-step="impact">
        <div class="esi-section-heading">
          <span class="esi-section-kicker">Step 2 of 4</span>
          <h2>Impact and urgency</h2>
          <p>Your answers help us estimate the right team and target response time.</p>
        </div>

        <div class="esi-two-column">
          <label>
            <span>Severity <em>Required</em></span>
            <select name="severity" data-routing-input required>
              <option value="">Select severity</option>
              <option value="752630000">Low</option>
              <option value="752630001">Medium</option>
              <option value="752630002">High</option>
              <option value="752630003">Critical</option>
            </select>
          </label>

          <label>
            <span>Priority <em>Required</em></span>
            <select name="priority" data-routing-input required>
              <option value="">Select priority</option>
              <option value="752630000">Low</option>
              <option value="752630001">Normal</option>
              <option value="752630002">High</option>
              <option value="752630003">Urgent</option>
            </select>
          </label>
        </div>

        <label>
          <span>Business impact <em data-critical-required>Required for urgent or critical requests</em></span>
          <textarea name="impact" rows="5" placeholder="Explain deadline risk, customer impact, affected team, or operational blocker."></textarea>
        </label>

        <div class="esi-step-error" data-step-error role="alert"></div>
        <div class="esi-action-bar">
          <button type="button" class="esi-secondary" data-prev-step="details">Back</button>
          <button type="button" class="esi-primary" data-next-step="documents">Continue to documents</button>
        </div>
      </section>

      <section class="esi-step" data-step="documents">
        <div class="esi-section-heading">
          <span class="esi-section-kicker">Step 3 of 4</span>
          <h2>Supporting files</h2>
          <p>Supporting files can be uploaded securely after your request record is created.</p>
        </div>

        <div class="esi-upload esi-upload-info">
          <span class="esi-upload-title">Upload after submission</span>
          <span class="esi-upload-help">After you submit, use the Upload supporting files action on the confirmation screen. Files are saved securely with this service request.</span>
          <ul>
            <li>Use screenshots, forms, approvals, or other evidence that explains the request.</li>
            <li>The upload area is tied to the confirmation number shown after submission.</li>
            <li>You can skip this step now if no files are needed.</li>
          </ul>
        </div>

        <div class="esi-step-error" data-step-error role="alert"></div>
        <div class="esi-action-bar">
          <button type="button" class="esi-secondary" data-prev-step="impact">Back</button>
          <button type="button" class="esi-primary" data-next-step="review">Review request</button>
        </div>
      </section>

      <section class="esi-step" data-step="review">
        <div class="esi-section-heading">
          <span class="esi-section-kicker">Step 4 of 4</span>
          <h2>Review and submit</h2>
          <p>Review your details before submitting. A confirmation number will be shown when your request is received.</p>
        </div>

        <div class="esi-review" data-review-summary></div>

        <label class="esi-check">
          <input type="checkbox" required />
          <span>I confirm the request details are accurate and ready to submit.</span>
        </label>

        <div class="esi-step-error" data-step-error role="alert"></div>
        <div class="esi-action-bar">
          <button type="button" class="esi-secondary" data-prev-step="documents">Back</button>
          <button type="submit" class="esi-primary">Submit service request</button>
        </div>
      </section>

      <div class="esi-result" data-submit-result role="status" aria-live="polite"></div>
    </form>

    <aside class="esi-preview" aria-live="polite" data-routing-preview>
      <div class="esi-preview-header">
        <span class="esi-preview-label">Routing preview</span>
        <span class="esi-preview-state">Waiting for inputs</span>
      </div>
      <h2>Complete category, severity, and priority to preview routing.</h2>
      <div class="esi-preview-grid">
        <div><span>Department</span><strong>Pending</strong></div>
        <div><span>Target response</span><strong>Pending</strong></div>
        <div><span>Review</span><strong>Pending</strong></div>
        <div><span>Supporting files</span><strong>Standard</strong></div>
      </div>
      <p>The final team and target response time are confirmed after you submit.</p>
    </aside>
  </div>
</main>

<script>
  window.esiPortalUser = {
    contactId: "{{ user.id }}",
    name: "{{ user.fullname | escape }}"
  };
</script>
{% else %}
<main class="esi-shell esi-auth-shell" id="mainContent">
  <section class="esi-auth-gate">
    <div>
      <span class="esi-preview-label">Secure intake</span>
      <h2>Sign in to submit a service request</h2>
      <p>Please sign in so we can link the request to your account and show only your own requests, uploaded files, and confirmation history.</p>
      <a class="esi-primary esi-link-button" href="{% if homeurl %}/{{ homeurl }}{% endif %}{{ website.sign_in_url_substitution }}">Sign in to continue</a>
    </div>
    <div class="esi-auth-panel" aria-label="Security controls">
      <strong>Why sign in?</strong>
      <ul>
        <li>Protects your request history</li>
        <li>Saves your contact details with the request</li>
        <li>Lets you track updates after submission</li>
      </ul>
    </div>
  </section>
</main>
{% endif %}
<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
  <div class="container" style="padding: 0px; display: flex; flex-wrap: wrap;"><div class="col-lg-12 columnBlockLayout" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px;"></div></div>
</div>
",
  "customcss": ":root {
  --esi-blue: #006fb6;
  --esi-blue-dark: #005a96;
  --esi-blue-soft: #e6f2fa;
  --esi-ink: #17202b;
  --esi-muted: #5d6b7b;
  --esi-line: #d9e1ea;
  --esi-line-strong: #b8c4d2;
  --esi-page: #f6f8fb;
  --esi-surface: #ffffff;
  --esi-surface-soft: #f8fafc;
  --esi-hint: #b8c2cc;
  --esi-green: #0f7b45;
  --esi-green-soft: #e7f6ee;
  --esi-amber: #9a5b00;
  --esi-amber-soft: #fff4e0;
  --esi-red: #b42318;
  --esi-red-soft: #fdecec;
  --esi-radius: 8px;
  --esi-shadow: 0 18px 50px rgba(23, 32, 43, 0.08);
}

body {
  background: var(--esi-page);
  color: var(--esi-ink);
}

.static-top.navbar-dark {
  background: var(--esi-surface) !important;
  border-bottom: 1px solid var(--esi-line);
  box-shadow: 0 2px 14px rgba(23, 32, 43, 0.06);
}

.static-top.navbar-dark .container.custom-container {
  max-width: 1180px;
}

.navbar-dark .navbar-nav > li > a,
.navbar-dark .navbar-nav > li.dropdown > a,
.static-top.navbar-dark .navbar-brand a span {
  color: var(--esi-ink) !important;
}

.navbar-dark .navbar-nav > li > a:hover,
.navbar-dark .navbar-nav > li.dropdown > a:hover,
.navbar-dark .navbar-nav > li > a:focus {
  color: var(--esi-blue) !important;
}

.esi-site-brand {
  align-items: center;
  color: var(--esi-ink);
  display: inline-flex;
  gap: 0;
  text-decoration: none;
}

.esi-site-logo {
  display: block;
  flex: 0 0 auto;
  height: auto;
  max-height: 50px;
  object-fit: contain;
  width: min(240px, 50vw);
}

.esi-site-title {
  font-size: 22px;
  font-weight: 800;
  letter-spacing: 0;
}

.esi-hero {
  background: linear-gradient(180deg, #eef7fc 0%, var(--esi-page) 88%);
  border-bottom: 1px solid rgba(217, 225, 234, 0.8);
  padding: 48px 24px 36px;
}

.esi-hero-inner,
.esi-shell {
  margin: 0 auto;
  max-width: 1180px;
}

.esi-hero-inner {
  align-items: flex-start;
  display: flex;
  gap: 32px;
  justify-content: space-between;
}

.esi-hero-copy {
  max-width: 820px;
}

.esi-hero h1 {
  color: var(--esi-blue-dark);
  font-family: "Segoe UI", Arial, sans-serif;
  font-size: 40px;
  font-weight: 700;
  letter-spacing: 0;
  line-height: 1.14;
  margin: 0 0 14px;
  text-wrap: balance;
}

.esi-hero p {
  color: var(--esi-muted);
  font-size: 18px;
  line-height: 1.55;
  margin: 0;
}

.esi-user-card {
  background: rgba(255, 255, 255, 0.88);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  box-shadow: 0 12px 34px rgba(23, 32, 43, 0.06);
  color: var(--esi-muted);
  display: grid;
  gap: 4px;
  min-width: 260px;
  padding: 18px;
}

.esi-user-card strong {
  color: var(--esi-ink);
  font-size: 16px;
}

.esi-user-label,
.esi-section-kicker,
.esi-preview-label {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-shell {
  padding: 28px 24px 56px;
}

.esi-workspace-banner,
.esi-form,
.esi-preview,
.esi-auth-gate {
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
}

.esi-workspace-banner {
  align-items: center;
  display: flex;
  gap: 16px;
  justify-content: space-between;
  margin-bottom: 20px;
  padding: 16px 18px;
}

.esi-workspace-banner div {
  display: grid;
  gap: 3px;
}

.esi-workspace-banner span:not(.esi-status-pill) {
  color: var(--esi-muted);
}

.esi-status-pill,
.esi-preview-state,
.esi-badge {
  border-radius: 999px;
  display: inline-flex;
  font-size: 12px;
  font-weight: 800;
  line-height: 1;
  padding: 8px 10px;
  white-space: nowrap;
}

.esi-status-pill,
.esi-preview-state.is-ready,
.esi-badge.is-green {
  background: var(--esi-green-soft);
  color: var(--esi-green);
}

.esi-preview-state,
.esi-badge {
  background: var(--esi-blue-soft);
  color: var(--esi-blue);
}

.esi-preview-state.is-warning,
.esi-badge.is-amber {
  background: var(--esi-amber-soft);
  color: var(--esi-amber);
}

.esi-preview-state.is-error,
.esi-badge.is-red {
  background: var(--esi-red-soft);
  color: var(--esi-red);
}

.esi-steps {
  display: grid;
  gap: 12px;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  margin-bottom: 24px;
}

.esi-steps button {
  align-items: center;
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  color: var(--esi-muted);
  cursor: pointer;
  display: flex;
  gap: 12px;
  min-height: 76px;
  padding: 14px;
  text-align: left;
}

.esi-steps button:hover {
  border-color: var(--esi-line-strong);
  box-shadow: 0 8px 22px rgba(23, 32, 43, 0.06);
}

.esi-steps button.is-active {
  border-color: var(--esi-blue);
  box-shadow: 0 0 0 3px rgba(0, 111, 182, 0.12);
  color: var(--esi-ink);
}

.esi-steps button.is-complete {
  border-color: rgba(15, 123, 69, 0.35);
}

.esi-step-index {
  align-items: center;
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 999px;
  color: var(--esi-muted);
  display: inline-flex;
  flex: 0 0 auto;
  font-weight: 800;
  height: 34px;
  justify-content: center;
  width: 34px;
}

.esi-steps button.is-active .esi-step-index {
  background: var(--esi-blue);
  border-color: var(--esi-blue);
  color: #ffffff;
}

.esi-steps button.is-complete .esi-step-index {
  background: var(--esi-green);
  border-color: var(--esi-green);
  color: #ffffff;
  font-size: 18px;
  line-height: 1;
}

.esi-steps strong,
.esi-steps small {
  display: block;
}

.esi-steps strong {
  color: var(--esi-ink);
  font-size: 14px;
  margin-bottom: 3px;
}

.esi-steps small {
  color: var(--esi-muted);
  font-size: 12px;
}

.esi-layout {
  align-items: start;
  display: grid;
  gap: 24px;
  grid-template-columns: minmax(0, 1fr) 360px;
}

.esi-form {
  box-shadow: var(--esi-shadow);
  overflow: hidden;
}

.esi-step {
  display: none;
  padding: 28px;
}

.esi-step.is-active {
  display: block;
}

.esi-section-heading {
  border-bottom: 1px solid var(--esi-line);
  margin: -2px 0 24px;
  padding-bottom: 20px;
}

.esi-section-heading h2,
.esi-preview h2,
.esi-auth-gate h2 {
  color: var(--esi-ink);
  font-size: 24px;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1.2;
  margin: 7px 0 8px;
}

.esi-section-heading p,
.esi-preview p,
.esi-auth-gate p,
.esi-muted {
  color: var(--esi-muted);
  line-height: 1.55;
  margin: 0;
}

.esi-two-column {
  display: grid;
  gap: 18px;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.esi-form label {
  color: var(--esi-ink);
  display: grid;
  font-weight: 700;
  gap: 8px;
  margin-bottom: 18px;
}

.esi-form label > span {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.esi-form label em {
  color: var(--esi-muted);
  font-size: 12px;
  font-style: normal;
  font-weight: 700;
}

.esi-form input,
.esi-form select,
.esi-form textarea {
  background: #ffffff;
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  color: var(--esi-ink);
  font: inherit;
  font-weight: 500;
  min-height: 46px;
  padding: 11px 12px;
  width: 100%;
}

.esi-form textarea {
  line-height: 1.5;
  min-height: 132px;
  resize: vertical;
}

.esi-form input::placeholder,
.esi-form textarea::placeholder {
  color: var(--esi-hint) !important;
  font-style: italic;
  font-weight: 400;
  opacity: 1;
}

.esi-form input:focus,
.esi-form select:focus,
.esi-form textarea:focus {
  border-color: var(--esi-blue);
  box-shadow: 0 0 0 3px rgba(0, 111, 182, 0.14);
  outline: none;
}

.esi-form input.is-invalid,
.esi-form select.is-invalid,
.esi-form textarea.is-invalid {
  border-color: var(--esi-red);
  box-shadow: 0 0 0 3px rgba(180, 35, 24, 0.1);
}

.esi-upload {
  background: var(--esi-surface-soft);
  border: 1px dashed var(--esi-line-strong);
  border-radius: var(--esi-radius);
  padding: 22px;
}

.esi-upload-title {
  color: var(--esi-ink);
  font-size: 16px;
  font-weight: 800;
}

.esi-upload-help {
  color: var(--esi-muted);
  font-size: 14px;
  font-weight: 500 !important;
}

.esi-upload-info {
  display: grid;
  gap: 10px;
}

.esi-upload-info ul {
  color: var(--esi-muted);
  display: grid;
  gap: 7px;
  line-height: 1.45;
  margin: 2px 0 0;
  padding-left: 20px;
}

.esi-file-list {
  display: grid;
  gap: 8px;
  margin-top: -4px;
}

.esi-file-list div {
  align-items: center;
  background: #ffffff;
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  color: var(--esi-muted);
  display: flex;
  gap: 10px;
  justify-content: space-between;
  padding: 10px 12px;
}

.esi-file-list strong {
  color: var(--esi-ink);
}

.esi-check {
  align-items: center;
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  display: flex !important;
  gap: 10px;
  padding: 14px;
}

.esi-check input {
  min-height: auto;
  width: auto;
}

.esi-review {
  display: grid;
  gap: 12px;
  margin-bottom: 18px;
}

.esi-review-row {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  display: grid;
  gap: 4px;
  padding: 13px 14px;
}

.esi-review-row span {
  color: var(--esi-muted);
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.esi-review-row strong {
  color: var(--esi-ink);
  font-size: 15px;
}

.esi-action-bar {
  align-items: center;
  background: rgba(255, 255, 255, 0.96);
  border-top: 1px solid var(--esi-line);
  bottom: 0;
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  margin: 28px -28px -28px;
  padding: 16px 28px;
  position: sticky;
  z-index: 2;
}

.esi-action-bar > span {
  color: var(--esi-muted);
  font-size: 14px;
  margin-right: auto;
}

.esi-primary,
.esi-secondary {
  align-items: center;
  border-radius: 6px;
  cursor: pointer;
  display: inline-flex;
  font-weight: 800;
  justify-content: center;
  min-height: 44px;
  padding: 11px 16px;
  text-decoration: none;
}

.esi-primary {
  background: var(--esi-blue);
  border: 1px solid var(--esi-blue);
  color: #ffffff;
}

.esi-primary:hover,
.esi-primary:focus {
  background: var(--esi-blue-dark);
  border-color: var(--esi-blue-dark);
  color: #ffffff;
  text-decoration: none;
}

.esi-secondary {
  background: #ffffff;
  border: 1px solid var(--esi-line-strong);
  color: var(--esi-ink);
}

.esi-secondary:hover,
.esi-secondary:focus {
  background: var(--esi-surface-soft);
  color: var(--esi-ink);
  text-decoration: none;
}

.esi-primary:focus-visible,
.esi-secondary:focus-visible,
.esi-steps button:focus-visible {
  outline: 3px solid rgba(0, 111, 182, 0.24);
  outline-offset: 2px;
}

.esi-primary:disabled {
  cursor: wait;
  opacity: 0.65;
}

.esi-step-error {
  background: var(--esi-red-soft);
  border: 1px solid rgba(180, 35, 24, 0.2);
  border-radius: 6px;
  color: var(--esi-red);
  display: none;
  font-weight: 800;
  margin-top: 8px;
  padding: 11px 12px;
}

.esi-step-error.is-visible {
  display: block;
}

.esi-result {
  border: 0;
  clip: rect(0 0 0 0);
  height: 1px;
  margin: -1px;
  overflow: hidden;
  padding: 0;
  position: absolute;
  white-space: nowrap;
  width: 1px;
}

.esi-submit-modal {
  display: none;
}

.esi-submit-modal.is-visible {
  align-items: center;
  display: flex;
  inset: 0;
  justify-content: center;
  padding: 24px;
  position: fixed;
  z-index: 2000;
}

.esi-submit-modal-backdrop {
  background: rgba(23, 32, 43, 0.45);
  inset: 0;
  position: absolute;
}

.esi-submit-dialog {
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-top: 5px solid var(--esi-blue);
  border-radius: var(--esi-radius);
  box-shadow: 0 28px 80px rgba(23, 32, 43, 0.28);
  display: grid;
  gap: 18px;
  max-width: 600px;
  outline: none;
  padding: 30px;
  position: relative;
  width: min(100%, 600px);
}

.esi-submit-modal.is-success .esi-submit-dialog {
  border-top-color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-dialog {
  border-top-color: var(--esi-red);
}

.esi-submit-icon {
  align-items: center;
  background: var(--esi-blue-soft);
  border-radius: 999px;
  color: var(--esi-blue);
  display: inline-flex;
  font-size: 15px;
  font-weight: 900;
  height: 48px;
  justify-content: center;
  width: 48px;
}

.esi-submit-modal.is-success .esi-submit-icon {
  background: var(--esi-green-soft);
  color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-icon {
  background: var(--esi-red-soft);
  color: var(--esi-red);
}

.esi-submit-modal.is-info .esi-submit-icon::before {
  animation: esi-spin 0.9s linear infinite;
  border: 3px solid rgba(0, 111, 182, 0.18);
  border-top-color: var(--esi-blue);
  border-radius: 999px;
  content: "";
  height: 24px;
  width: 24px;
}

.esi-submit-content {
  display: grid;
  gap: 10px;
}

.esi-submit-kicker {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 900;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-submit-modal.is-success .esi-submit-kicker {
  color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-kicker {
  color: var(--esi-red);
}

.esi-submit-content h2 {
  color: var(--esi-ink);
  font-size: 28px;
  font-weight: 800;
  line-height: 1.15;
  margin: 0;
}

.esi-submit-content p {
  color: var(--esi-muted);
  font-size: 16px;
  line-height: 1.55;
  margin: 0;
}

.esi-confirmation-number {
  background: var(--esi-blue-soft);
  border: 1px solid rgba(0, 111, 182, 0.18);
  border-radius: var(--esi-radius);
  display: grid;
  gap: 4px;
  margin-top: 4px;
  padding: 14px 16px;
}

.esi-confirmation-number span {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 900;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-confirmation-number strong {
  color: var(--esi-blue-dark);
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 0.02em;
}

.esi-submit-next {
  color: var(--esi-muted);
  display: grid;
  gap: 7px;
  line-height: 1.45;
  margin: 4px 0 0;
  padding-left: 20px;
}

.esi-submit-actions {
  border-top: 1px solid var(--esi-line);
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: flex-end;
  padding-top: 18px;
}

@keyframes esi-spin {
  to {
    transform: rotate(360deg);
  }
}

.esi-preview {
  box-shadow: 0 12px 30px rgba(23, 32, 43, 0.06);
  padding: 22px;
  position: sticky;
  top: 18px;
}

.esi-preview-header {
  align-items: center;
  display: flex;
  gap: 10px;
  justify-content: space-between;
  margin-bottom: 12px;
}

.esi-preview h2 {
  font-size: 22px;
  margin-bottom: 18px;
}

.esi-preview-grid {
  display: grid;
  gap: 10px;
  margin: 18px 0;
}

.esi-preview-grid div {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  display: grid;
  gap: 5px;
  padding: 12px;
}

.esi-preview-grid span {
  color: var(--esi-muted);
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.esi-preview-grid strong {
  color: var(--esi-ink);
  font-size: 15px;
}

.esi-preview-grid .esi-badge {
  color: var(--esi-blue);
  font-size: 12px;
  width: max-content;
}

.esi-preview-grid .esi-badge.is-green {
  color: var(--esi-green);
}

.esi-preview-grid .esi-badge.is-amber {
  color: var(--esi-amber);
}

.esi-preview-grid .esi-badge.is-red {
  color: var(--esi-red);
}

.esi-preview-note {
  background: var(--esi-blue-soft);
  border-radius: 6px;
  color: var(--esi-muted);
  margin-top: 16px;
  padding: 12px;
}

.esi-auth-shell {
  padding-top: 40px;
}

.esi-auth-gate {
  align-items: stretch;
  box-shadow: var(--esi-shadow);
  display: grid;
  gap: 24px;
  grid-template-columns: minmax(0, 1fr) 340px;
  padding: 34px;
}

.esi-auth-gate h2 {
  font-size: 30px;
}

.esi-auth-gate .esi-link-button {
  margin-top: 22px;
}

.esi-auth-panel {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  padding: 22px;
}

.esi-auth-panel strong {
  display: block;
  margin-bottom: 12px;
}

.esi-auth-panel ul {
  color: var(--esi-muted);
  display: grid;
  gap: 10px;
  margin: 0;
  padding-left: 18px;
}

@media (max-width: 980px) {
  .esi-hero-inner,
  .esi-workspace-banner {
    display: grid;
  }

  .esi-user-card {
    min-width: 0;
  }

  .esi-steps {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .esi-layout,
  .esi-auth-gate {
    grid-template-columns: 1fr;
  }

  .esi-preview {
    position: static;
  }
}

@media (max-width: 640px) {
  .esi-hero {
    padding: 34px 18px 28px;
  }

  .esi-hero h1 {
    font-size: 31px;
  }

  .esi-shell {
    padding: 20px 16px 40px;
  }

  .esi-steps {
    display: grid;
    gap: 8px;
    grid-template-columns: 1fr;
  }

  .esi-steps button {
    min-height: 64px;
  }

  .esi-two-column {
    grid-template-columns: 1fr;
  }

  .esi-step {
    padding: 22px;
  }

  .esi-action-bar {
    align-items: stretch;
    flex-direction: column;
    margin: 24px -22px -22px;
    padding: 14px 22px;
    position: static;
  }

  .esi-action-bar > span {
    margin-right: 0;
  }

  .esi-primary,
  .esi-secondary {
    width: 100%;
  }

  .esi-submit-modal.is-visible {
    align-items: flex-end;
    padding: 16px;
  }

  .esi-submit-dialog {
    padding: 24px;
  }

  .esi-submit-content h2 {
    font-size: 24px;
  }

  .esi-submit-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .esi-preview-header,
  .esi-workspace-banner {
    align-items: stretch;
  }

  .esi-site-logo {
    max-height: 38px;
    width: min(190px, 58vw);
  }
}
",
  "customjavascript": "(function () {
  const root = document.querySelector("[data-esi-intake]");
  if (!root) return;

  const preview = root.querySelector("[data-routing-preview]");
  const review = root.querySelector("[data-review-summary]");
  const result = root.querySelector("[data-submit-result]");
  const form = root.querySelector(".esi-form");
  const submitButton = root.querySelector('button[type="submit"]');
  const steps = Array.from(root.querySelectorAll("[data-step]")).map((item) => item.dataset.step);
  const stepButtons = Array.from(root.querySelectorAll("[data-step-target]"));
  let resultModal = null;
  let cachedRules = null;
  let cachedCategories = null;
  let currentStep = "details";

  function field(name) {
    return root.querySelector(`[name="${name}"]`);
  }

  function selectedOption(name) {
    return field(name)?.selectedOptions?.[0] || null;
  }

  function selectedText(name) {
    const option = selectedOption(name);
    return option && option.value ? option.textContent.trim() : "";
  }

  function selectedCategoryName() {
    return selectedText("category");
  }

  function html(value) {
    const element = document.createElement("span");
    element.textContent = value == null ? "" : String(value);
    return element.innerHTML;
  }

  function stepIndex(stepName) {
    return steps.indexOf(stepName);
  }

  function stepPanel(stepName) {
    return root.querySelector(`[data-step="${stepName}"]`);
  }

  function stepError(stepName) {
    return stepPanel(stepName)?.querySelector("[data-step-error]");
  }

  function setStepError(stepName, message) {
    const error = stepError(stepName);
    if (!error) return;
    error.textContent = message || "";
    error.classList.toggle("is-visible", Boolean(message));
  }

  function controlsForStep(stepName) {
    return Array.from(stepPanel(stepName)?.querySelectorAll("input, select, textarea") || [])
      .filter((control) => !control.disabled && control.type !== "button" && control.type !== "submit");
  }

  function isHighImpactRequest() {
    const severity = Number(field("severity")?.value || 0);
    const priority = Number(field("priority")?.value || 0);
    return severity >= 752630002 || priority >= 752630002;
  }

  function applyConditionalRequirements() {
    const impact = field("impact");
    const note = root.querySelector("[data-critical-required]");
    const required = isHighImpactRequest();
    if (!impact) return;

    impact.required = required;
    impact.setCustomValidity(required && !impact.value.trim()
      ? "Business impact is required for urgent or critical requests."
      : "");

    if (note) {
      note.textContent = required
        ? "Required for this request"
        : "Required for urgent or critical requests";
    }
  }

  function validateStep(stepName) {
    applyConditionalRequirements();
    const controls = controlsForStep(stepName);
    const invalid = controls.find((control) => !control.checkValidity());

    controls.forEach((control) => {
      control.classList.toggle("is-invalid", !control.checkValidity());
    });

    if (invalid) {
      const message = invalid.validationMessage || "Complete the required fields on this step before continuing.";
      setStepError(stepName, message);
      invalid.reportValidity();
      invalid.focus({ preventScroll: false });
      return false;
    }

    setStepError(stepName, "");
    return true;
  }

  function validateBefore(targetStep) {
    const targetIndex = stepIndex(targetStep);
    const currentIndex = stepIndex(currentStep);
    if (targetIndex <= currentIndex) return true;

    for (let index = currentIndex; index < targetIndex; index += 1) {
      const stepName = steps[index];
      if (stepName !== currentStep) setActiveStep(stepName);
      if (!validateStep(stepName)) return false;
    }
    return true;
  }

  function setActiveStep(stepName) {
    if (!steps.includes(stepName)) return;

    currentStep = stepName;
    const activeIndex = stepIndex(stepName);

    root.querySelectorAll("[data-step]").forEach((item) => {
      item.classList.toggle("is-active", item.dataset.step === stepName);
    });

    stepButtons.forEach((button, index) => {
      const isActive = button.dataset.stepTarget === stepName;
      const isComplete = index < activeIndex;
      const stepIndexBadge = button.querySelector(".esi-step-index");
      button.classList.toggle("is-active", isActive);
      button.classList.toggle("is-complete", isComplete);
      if (stepIndexBadge) {
        stepIndexBadge.textContent = isComplete ? "✓" : String(index + 1);
        stepIndexBadge.setAttribute("aria-hidden", "true");
      }
      if (isActive) {
        button.setAttribute("aria-current", "step");
      } else {
        button.removeAttribute("aria-current");
      }
    });

    applyConditionalRequirements();
    updateReview();
  }

  function goToStep(stepName) {
    if (!validateBefore(stepName)) return;
    setActiveStep(stepName);
  }

  function safeAjax(options) {
    const tokenProvider = window.shell && window.shell.getTokenDeferred;
    if (!window.jQuery || !tokenProvider) {
      return Promise.reject(new Error("We could not prepare the secure request. Refresh the page and try again."));
    }

    return new Promise((resolve, reject) => {
      tokenProvider().done((token) => {
        const headers = Object.assign({
          Accept: "application/json",
          "Content-Type": "application/json",
          "__RequestVerificationToken": token
        }, options.headers || {});

        window.jQuery.ajax(Object.assign({}, options, { headers }))
          .done((data, textStatus, xhr) => resolve({ data, xhr }))
          .fail((xhr) => {
            const detail = xhr.responseJSON?.error?.message || xhr.responseText || xhr.statusText;
            reject(new Error(detail || `Request failed with status ${xhr.status}`));
          });
      }).fail(() => reject(new Error("We could not prepare the secure request. Refresh the page and try again.")));
    });
  }

  async function loadCategories() {
    if (cachedCategories) return cachedCategories;
    const response = await safeAjax({
      method: "GET",
      url: "/_api/hx_servicecategories?$select=hx_servicecategoryid,hx_name&$filter=hx_active eq true&$orderby=hx_name asc"
    });
    cachedCategories = response.data.value || [];
    return cachedCategories;
  }

  async function populateCategories() {
    const category = field("category");
    try {
      const categories = await loadCategories();
      category.innerHTML = '<option value="">Select a category</option>' + categories
        .map((item) => `<option value="${html(item.hx_servicecategoryid)}">${html(item.hx_name)}</option>`)
        .join("");
    } catch (error) {
      category.innerHTML = [
        '<option value="">Select a category</option>',
        '<option value="static-funding">Funding Agreement</option>',
        '<option value="static-research">Research Partnership</option>',
        '<option value="static-event">Event Support</option>',
        '<option value="static-tech">Technical Support</option>',
        '<option value="static-general">General Inquiry</option>'
      ].join("");
      setPreview({
        status: "warning",
        heading: "Categories are temporarily unavailable.",
        note: "You can still review the form, but submitting requires an active service category."
      });
    }
  }

  async function loadRules() {
    if (cachedRules) return cachedRules;

    const query = [
      "/_api/hx_routingrules",
      "?$select=hx_name,hx_matchseverity,hx_matchpriority,hx_requiresapproval,hx_resolutiondocumentationrequired,hx_sortorder",
      "&$expand=hx_Servicecategory($select=hx_name),hx_Department($select=hx_name),hx_Slapolicy($select=hx_responsehours)",
      "&$filter=hx_active eq true",
      "&$orderby=hx_sortorder asc"
    ].join("");

    const response = await safeAjax({ method: "GET", url: query });
    cachedRules = (response.data.value || []).map((rule) => ({
      name: rule.hx_name,
      category: rule.hx_Servicecategory?.hx_name,
      severity: Number(rule.hx_matchseverity),
      priority: Number(rule.hx_matchpriority),
      department: rule.hx_Department?.hx_name,
      responseHours: rule.hx_Slapolicy?.hx_responsehours,
      requiresApproval: Boolean(rule.hx_requiresapproval),
      requiresDocumentation: Boolean(rule.hx_resolutiondocumentationrequired)
    }));
    return cachedRules;
  }

  function previewStateLabel(status) {
    if (status === "ready") return "Estimate ready";
    if (status === "warning") return "Needs review";
    if (status === "error") return "Unavailable";
    if (status === "loading") return "Checking options";
    return "Waiting for details";
  }

  function toneFor(value, kind) {
    if (kind === "approval" && /required/i.test(value || "")) return "is-amber";
    if (kind === "documentation" && /required|evidence/i.test(value || "")) return "is-red";
    if (/pending|unavailable/i.test(value || "")) return "";
    return "is-green";
  }

  function previewRow(label, value, toneClass) {
    return `
      <div>
        <span>${html(label)}</span>
        ${toneClass ? `<strong class="esi-badge ${toneClass}">${html(value)}</strong>` : `<strong>${html(value)}</strong>`}
      </div>`;
  }

  function setPreview(state) {
    const department = state.department || "Pending";
    const sla = state.sla || "Pending";
    const approval = state.approval || "Pending";
    const documentation = state.documentation || "Standard";
    const status = state.status || "waiting";
    const stateClass = status === "ready" ? "is-ready" : status === "warning" ? "is-warning" : status === "error" ? "is-error" : "";

    preview.innerHTML = `
      <div class="esi-preview-header">
        <span class="esi-preview-label">Routing preview</span>
        <span class="esi-preview-state ${stateClass}">${html(previewStateLabel(status))}</span>
      </div>
      <h2>${html(state.heading)}</h2>
      <div class="esi-preview-grid">
        ${previewRow("Department", department)}
      ${previewRow("Target response", sla)}
      ${previewRow("Review", approval, toneFor(approval, "approval"))}
      ${previewRow("Supporting files", documentation, toneFor(documentation, "documentation"))}
      </div>
      <p class="esi-preview-note">${html(state.note || "The final team and target response time are confirmed after you submit.")}</p>`;
  }

  async function refreshPreview() {
    applyConditionalRequirements();
    const category = selectedCategoryName();
    const severity = Number(field("severity")?.value || 0);
    const priority = Number(field("priority")?.value || 0);

    if (!category || !severity || !priority) {
      setPreview({
        status: "waiting",
        heading: "Complete category, severity, and priority to preview routing.",
        note: "The final team and target response time are confirmed after you submit."
      });
      return;
    }

    setPreview({
      status: "loading",
      heading: "Refreshing live routing preview...",
      note: "Checking the current service options for your request."
    });

    try {
      const rules = await loadRules();
      const match = rules.find((rule) =>
        rule.category === category &&
        rule.severity === severity &&
        rule.priority === priority);

      if (!match) {
        setPreview({
          status: "warning",
          heading: "General Intake review expected",
          department: "General Intake",
          sla: "Reviewed after submission",
          approval: isHighImpactRequest() ? "Additional review may be required" : "To be confirmed",
          documentation: isHighImpactRequest() ? "Impact details required" : "As needed",
          note: "We will review this request after submission and assign it to the right team."
        });
        return;
      }

      setPreview({
        status: "ready",
        heading: match.name,
        department: match.department,
        sla: `${match.responseHours} hour response target`,
        approval: match.requiresApproval ? "Additional review required" : "No additional review expected",
        documentation: match.requiresDocumentation ? "Follow-up details may be required" : "Standard supporting files",
        note: "This is an estimate. The final team and target response time are confirmed after you submit."
      });
    } catch (error) {
      setPreview({
        status: "error",
        heading: "Preview temporarily unavailable",
        department: "Assigned after submission",
        sla: "Confirmed after submission",
        approval: isHighImpactRequest() ? "Additional review may be required" : "To be confirmed",
        documentation: isHighImpactRequest() ? "Impact details required" : "Standard",
        note: "We could not show an estimate right now. You can still submit the request."
      });
    }
  }

  function summaryValue(value, fallback) {
    return value && String(value).trim() ? String(value).trim() : fallback;
  }

  function reviewRow(label, value) {
    return `
      <div class="esi-review-row">
        <span>${html(label)}</span>
        <strong>${html(value)}</strong>
      </div>`;
  }

  function updateReview() {
    if (!review) return;
    review.innerHTML = [
      reviewRow("Title", summaryValue(field("title")?.value, "Not entered")),
      reviewRow("Category", summaryValue(selectedCategoryName(), "Not selected")),
      reviewRow("Severity", summaryValue(selectedText("severity"), "Not selected")),
      reviewRow("Priority", summaryValue(selectedText("priority"), "Not selected")),
      reviewRow("Business impact", summaryValue(field("impact")?.value, "Not provided")),
      reviewRow("Supporting files", "Secure upload available after submission")
    ].join("");
  }

  function ensureResultModal() {
    if (resultModal) return resultModal;

    resultModal = document.createElement("div");
    resultModal.className = "esi-submit-modal";
    resultModal.setAttribute("aria-hidden", "true");
    document.body.appendChild(resultModal);

    resultModal.addEventListener("click", (event) => {
      const action = event.target.closest("[data-result-action]")?.dataset.resultAction;
      if (!action || resultModal.dataset.locked === "true") return;

      if (action === "new") {
        closeResult();
        setActiveStep("details");
        window.scrollTo({ top: root.offsetTop - 20, behavior: "smooth" });
        field("title")?.focus({ preventScroll: true });
      }

      if (action === "documents") {
        const url = event.target.closest("[data-result-url]")?.dataset.resultUrl;
        if (url) window.location.href = url;
      }

      if (action === "review") {
        closeResult();
        setActiveStep("review");
        submitButton?.focus({ preventScroll: false });
      }

      if (action === "close") {
        const wasSuccess = resultModal.classList.contains("is-success");
        closeResult();
        if (wasSuccess) {
          field("title")?.focus({ preventScroll: false });
        } else {
          submitButton?.focus({ preventScroll: false });
        }
      }
    });

    document.addEventListener("keydown", (event) => {
      if (event.key === "Escape" && resultModal?.classList.contains("is-visible") && resultModal.dataset.locked !== "true") {
        const wasSuccess = resultModal.classList.contains("is-success");
        closeResult();
        if (wasSuccess) {
          field("title")?.focus({ preventScroll: false });
        } else {
          submitButton?.focus({ preventScroll: false });
        }
      }
    });

    return resultModal;
  }

  function resultIcon(tone) {
    if (tone === "success") return "OK";
    if (tone === "error") return "!";
    return "";
  }

  function resultActions(tone, options = {}) {
    if (tone === "success") {
      return `
        ${options.documentsUrl ? `<button type="button" class="esi-primary" data-result-action="documents" data-result-url="${html(options.documentsUrl)}">Upload supporting files</button>` : ""}
        <button type="button" class="esi-secondary" data-result-action="new">Submit another request</button>
        <button type="button" class="esi-secondary" data-result-action="close">Close</button>`;
    }

    if (tone === "error") {
      return `
        <button type="button" class="esi-primary" data-result-action="review">Review and try again</button>
        <button type="button" class="esi-secondary" data-result-action="close">Close</button>`;
    }

    return "";
  }

  function showResult(tone, title, body, options = {}) {
    const modal = ensureResultModal();
    const toneClass = tone === "success" ? "is-success" : tone === "error" ? "is-error" : "is-info";
    const confirmation = options.confirmation || "";

    result.className = `esi-result is-visible ${tone === "success" ? "is-success" : tone === "error" ? "is-error" : ""}`;
    result.textContent = `${title}. ${body}`;

    modal.dataset.locked = tone === "info" ? "true" : "false";
    modal.className = `esi-submit-modal is-visible ${toneClass}`;
    modal.setAttribute("aria-hidden", "false");
    modal.innerHTML = `
      <div class="esi-submit-modal-backdrop" data-result-action="${tone === "info" ? "" : "close"}"></div>
      <section class="esi-submit-dialog" role="dialog" aria-modal="true" aria-labelledby="esi-submit-title" aria-describedby="esi-submit-message" tabindex="-1">
        <div class="esi-submit-icon" aria-hidden="true">${html(resultIcon(tone))}</div>
        <div class="esi-submit-content">
          <span class="esi-submit-kicker">${tone === "success" ? "Submitted" : tone === "error" ? "Action needed" : "Sending request"}</span>
          <h2 id="esi-submit-title">${html(title)}</h2>
          <p id="esi-submit-message">${html(body)}</p>
          ${confirmation ? `
            <div class="esi-confirmation-number">
              <span>Confirmation number</span>
              <strong>${html(confirmation)}</strong>
            </div>` : ""}
          ${tone === "success" ? `
            <ul class="esi-submit-next">
              <li>Your request is now linked to your portal account.</li>
              <li>Supporting files can be uploaded securely after submission.</li>
              <li>Mitacs will confirm routing, review needs, and response timing after submission.</li>
            </ul>` : ""}
        </div>
        ${resultActions(tone, options) ? `<div class="esi-submit-actions">${resultActions(tone, options)}</div>` : ""}
      </section>`;

    modal.querySelector(".esi-submit-dialog")?.focus({ preventScroll: true });
  }

  function closeResult() {
    if (!resultModal) return;
    resultModal.className = "esi-submit-modal";
    resultModal.setAttribute("aria-hidden", "true");
    resultModal.dataset.locked = "false";
    resultModal.innerHTML = "";
  }

  function clearResult() {
    result.className = "esi-result";
    result.innerHTML = "";
    closeResult();
  }

  function extractCreatedId(xhr) {
    const entityId = xhr.getResponseHeader("entityid") || xhr.getResponseHeader("OData-EntityId") || "";
    const match = entityId.match(/\(([^)]+)\)/);
    return match ? match[1] : entityId;
  }

  async function submitRequest(event) {
    event.preventDefault();
    if (!validateBefore("review") || !validateStep("review") || !form.reportValidity()) return;

    const categoryId = field("category").value;
    if (/^static-/.test(categoryId)) {
      showResult("error", "Service category unavailable", "We could not load the current service categories. Refresh the page and try again before submitting.");
      return;
    }

    submitButton.disabled = true;
    showResult("info", "Submitting request...", "Creating your request. Supporting files can be uploaded after the confirmation number is assigned.");

    const descriptionParts = [
      field("description").value,
      field("impact").value ? `Business impact: ${field("impact").value}` : ""
    ].filter(Boolean);

    const payload = {
      hx_title: field("title").value,
      hx_description: descriptionParts.join("\n\n"),
      hx_severity: Number(field("severity").value),
      hx_priority: Number(field("priority").value),
      hx_submittedon: new Date().toISOString(),
      "hx_Servicecategory@odata.bind": `/hx_servicecategories(${categoryId})`
    };

    if (window.esiPortalUser?.contactId) {
      payload["hx_Customercontact@odata.bind"] = `/contacts(${window.esiPortalUser.contactId})`;
    }

    try {
      const createResponse = await safeAjax({
        method: "POST",
        url: "/_api/hx_servicerequests",
        data: JSON.stringify(payload)
      });
      const requestId = extractCreatedId(createResponse.xhr);

      let confirmation = "";
      if (requestId) {
        try {
          const created = await safeAjax({
            method: "GET",
            url: `/_api/hx_servicerequests(${requestId})?$select=hx_confirmationnumber,hx_routingpreviewsummary`
          });
          confirmation = created.data.hx_confirmationnumber || "";
        } catch {
          confirmation = "";
        }
      }

      showResult(
        "success",
        "Request submitted",
        confirmation
          ? "Your request has been received. Save this confirmation number if you need to follow up with Mitacs."
          : "Your request has been received. A confirmation number will be available after processing.",
        {
          confirmation,
          documentsUrl: requestId ? `/request-documents/?id=${encodeURIComponent(requestId)}` : ""
        }
      );

      form.reset();
      setActiveStep("details");
      updateReview();
      await populateCategories();
      await refreshPreview();
    } catch (error) {
      console.error(error);
      showResult("error", "Submission failed", "We could not submit your request. Your information is still on the form. Please review the details and try again.");
    } finally {
      submitButton.disabled = false;
    }
  }

  stepButtons.forEach((button) => {
    button.addEventListener("click", () => goToStep(button.dataset.stepTarget));
  });

  root.querySelectorAll("[data-next-step]").forEach((button) => {
    button.addEventListener("click", () => goToStep(button.dataset.nextStep));
  });

  root.querySelectorAll("[data-prev-step]").forEach((button) => {
    button.addEventListener("click", () => setActiveStep(button.dataset.prevStep));
  });

  root.querySelectorAll("input, select, textarea").forEach((control) => {
    control.addEventListener("input", () => {
      applyConditionalRequirements();
      if (control.checkValidity()) control.classList.remove("is-invalid");
      setStepError(control.closest("[data-step]")?.dataset.step, "");
      updateReview();
      if (result.classList.contains("is-error")) clearResult();
    });
  });

  root.querySelectorAll("[data-routing-input]").forEach((input) => {
    input.addEventListener("change", () => {
      refreshPreview();
      updateReview();
    });
  });

  form?.addEventListener("submit", submitRequest);

  setActiveStep("details");
  populateCategories().then(refreshPreview);
})();
